## \brief Reads input from a file with the given file name
# \param filename name of the input file
# \return mass of the first star (kg)
# \return mass of the second star (kg)
# \return initial x-position of the first star (m)
# \return initial y-position of the first star (m)
# \return initial x-position of the second star (m)
# \return initial y-position of the second star (m)
# \return initial x-velocity of the first star (m/s)
# \return initial y-velocity of the first star (m/s)
# \return initial x-velocity of the second star (m/s)
# \return initial y-velocity of the second star (m/s)
# \return final time (s)
def get_input(filename):
    infile = open(filename, "r")
    infile.readline()
    m_1 = float(infile.readline())
    infile.readline()
    m_2 = float(infile.readline())
    infile.readline()
    x_1_0 = float(infile.readline())
    infile.readline()
    y_1_0 = float(infile.readline())
    infile.readline()
    x_2_0 = float(infile.readline())
    infile.readline()
    y_2_0 = float(infile.readline())
    infile.readline()
    v_x1_0 = float(infile.readline())
    infile.readline()
    v_y1_0 = float(infile.readline())
    infile.readline()
    v_x2_0 = float(infile.readline())
    infile.readline()
    v_y2_0 = float(infile.readline())
    infile.readline()
    t_final = float(infile.readline())
    infile.close()
    
    return m_1, m_2, x_1_0, y_1_0, x_2_0, y_2_0, v_x1_0, v_y1_0, v_x2_0, v_y2_0, t_final

